content.outputFormat:
For each test case print a single JSON object on its own line representing the result of the operation.
- add / update → {"id": id, "name": "name", "CGPA": cgpa, "age": age}
- delete       → {"id": id}
- search       → {"name": "name"}
- sort         → {"sorted_by": "field"}
All keys and string values must be quoted exactly as shown, numbers must not be quoted, and a single space follows each comma.

code.C:
#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char op[10];
        scanf("%s", op);
        if (strcmp(op, "add") == 0 || strcmp(op, "update") == 0) {
            int id, age;
            char name[25];
            double cgpa;
            scanf("%d %s %lf %d", &id, name, &cgpa, &age);
            printf("{\"id\": %d, \"name\": \"%s\", \"CGPA\": %g, \"age\": %d}\n", id, name, cgpa, age);
        } else if (strcmp(op, "delete") == 0) {
            int id;
            scanf("%d", &id);
            printf("{\"id\": %d}\n", id);
        } else if (strcmp(op, "search") == 0) {
            char name[25];
            scanf("%s", name);
            printf("{\"name\": \"%s\"}\n", name);
        } else if (strcmp(op, "sort") == 0) {
            char field[10];
            scanf("%s", field);
            printf("{\"sorted_by\": \"%s\"}\n", field);
        }
    }
    return 0;
}

