code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            String line = br.readLine();
            StringTokenizer st = new StringTokenizer(line);
            String op = st.nextToken();
            switch (op) {
                case "add":
                case "update": {
                    long id = Long.parseLong(st.nextToken());
                    String name = st.nextToken();
                    double cgpa = Double.parseDouble(st.nextToken());
                    int age = Integer.parseInt(st.nextToken());
                    out.append('{').append("\"id\": ").append(id)
                       .append(", \"name\": \"").append(name).append('\"')
                       .append(", \"CGPA\": ").append(cgpa)
                       .append(", \"age\": ").append(age).append('}').append('\n');
                    break;
                }
                case "delete": {
                    long id = Long.parseLong(st.nextToken());
                    out.append('{').append("\"id\": ").append(id).append('}').append('\n');
                    break;
                }
                case "search": {
                    String name = st.nextToken();
                    out.append('{').append("\"name\": \"").append(name).append('\"').append('}').append('\n');
                    break;
                }
                case "sort": {
                    String field = st.nextToken();
                    out.append('{').append("\"sorted_by\": \"").append(field).append('\"').append('}').append('\n');
                    break;
                }
            }
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def main():
    data = sys.stdin.read().strip().split('\n')
    if not data:
        return
    T = int(data[0])
    out_lines = []
    for i in range(1, T+1):
        parts = data[i].split()
        op = parts[0]
        if op in ('add', 'update'):
            id_, name, cgpa, age = parts[1], parts[2], parts[3], parts[4]
            out_lines.append(f'{{"id": {int(id_)}, "name": "{name}", "CGPA": {float(cgpa)}, "age": {int(age)}}}')
        elif op == 'delete':
            id_ = parts[1]
            out_lines.append(f'{{"id": {int(id_)}}}')
        elif op == 'search':
            name = parts[1]
            out_lines.append(f'{{"name": "{name}"}}')
        elif op == 'sort':
            field = parts[1]
            out_lines.append(f'{{"sorted_by": "{field}"}}')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

