const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++], 10);
let out = [];
for (let t = 0; t < T; t++) {
  const tokens = lines[idx++].trim().split(/\s+/);
  const op = tokens[0];
  if (op === 'add' || op === 'update') {
    const id = parseInt(tokens[1], 10);
    const name = tokens[2];
    const cgpa = parseFloat(tokens[3]);
    const age = parseInt(tokens[4], 10);
    out.push(`{"id": ${id}, "name": "${name}", "CGPA": ${cgpa}, "age": ${age}}`);
  } else if (op === 'delete') {
    const id = parseInt(tokens[1], 10);
    out.push(`{"id": ${id}}`);
  } else if (op === 'search') {
    const name = tokens[1];
    out.push(`{"name": "${name}"}`);
  } else if (op === 'sort') {
    const field = tokens[1];
    out.push(`{"sorted_by": "${field}"}`);
  }
}
